import { index, integer, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const creditWalletLedger = pgTable(
  "credit_wallet_ledger",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    ownerId: text("owner_id"),
    organizationId: text("organization_id"),
    idempotencyKey: text("idempotency_key"),
    direction: text("direction").notNull(),
    amount: integer("amount").notNull(),
    reason: text("reason").notNull(),
    source: text("source"),
    metadata: jsonb("metadata").$type<Record<string, unknown>>().notNull().default({}),
    expiresAt: timestamp("expires_at", { withTimezone: true }),
    createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (item) => [
    index("credit_wallet_owner_idx").on(item.ownerId),
    index("credit_wallet_organization_idx").on(item.organizationId),
    index("credit_wallet_idempotency_idx").on(item.idempotencyKey),
  ]
);

export type CreditLedgerEntry = {
  direction: "grant" | "consume" | "refund" | "expire";
  amount: number;
  reason: string;
  idempotencyKey?: string;
  metadata?: Record<string, unknown>;
};

export function createCreditLedgerEntry(entry: CreditLedgerEntry) {
  if (!Number.isInteger(entry.amount) || entry.amount <= 0) {
    throw new Error("Credit ledger amount must be a positive integer.");
  }

  return {
    direction: entry.direction,
    amount: entry.amount,
    reason: entry.reason,
    idempotencyKey: entry.idempotencyKey,
    metadata: entry.metadata ?? {},
  };
}

export function calculateCreditBalance(entries: CreditLedgerEntry[]) {
  return entries.reduce((balance, entry) => {
    if (entry.direction === "grant" || entry.direction === "refund") return balance + entry.amount;
    return balance - entry.amount;
  }, 0);
}

export function assertSufficientCredits(balance: number, amount: number) {
  if (balance < amount) {
    throw new Error("Insufficient credits.");
  }
}

const checklist = [
  "Grant credits through checkout, admin action, or promotion.",
  "Consume credits with an idempotency key for every billable action.",
  "Block usage before a balance can become negative.",
  "Show low-balance and upgrade prompts before users get stuck.",
];

export default function CreditWalletPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Credit Wallet</h1>
        <p className="text-muted-foreground">Prepaid credit ledger for AI, usage, and credit-pack billing.</p>
      </div>
      <div className="grid gap-3">
        {checklist.map((item) => (
          <div key={item} className="rounded-lg border p-4 text-sm">{item}</div>
        ))}
      </div>
    </main>
  );
}
